/**
 * Fetch grocer dashboard statistics
 */
async function getGrocerStats(grocerId: string) {
  const now = new Date();
  const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
  const startOfLastMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
  const endOfLastMonth = new Date(now.getFullYear(), now.getMonth(), 0);

  // Execute all queries in parallel
  const [
    totalOrders,
    activeOrders,
    thisMonthOrders,
    lastMonthOrders,
    thisMonthSpending,
    lastMonthSpending,
    favoriteFarmers,
    grocer,
  ] = await Promise.all([
    // Total orders
    prisma.order.count({
      where: { grocerId },
    }),

    // Active orders (not delivered or cancelled)
    prisma.order.count({
      where: {
        grocerId,
        status: { notIn: ["DELIVERED", "CANCELLED", "REFUNDED"] },
      },
    }),

    // This month orders
    prisma.order.count({
      where: { grocerId, createdAt: { gte: startOfMonth } },
    }),

    // Last month orders
    prisma.order.count({
      where: {
        grocerId,
        createdAt: { gte: startOfLastMonth, lte: endOfLastMonth },
      },
    }),

    // This month spending
    prisma.order.aggregate({
      where: {
        grocerId,
        status: { notIn: ["CANCELLED", "REFUNDED"] },
        createdAt: { gte: startOfMonth },
      },
      _sum: { total: true },
    }),

    // Last month spending
    prisma.order.aggregate({
      where: {
        grocerId,
        status: { notIn: ["CANCELLED", "REFUNDED"] },
        createdAt: { gte: startOfLastMonth, lte: endOfLastMonth },
      },
      _sum: { total: true },
    }),

    // Favorite farmers count
    prisma.favoriteFarmer.count({
      where: { grocerId },
    }),

    // Grocer profile
    prisma.grocer.findUnique({
      where: { id: grocerId },
      select: { businessName: true },
    }),
  ]);

  // Calculate percentage changes
  const thisMonthSpendingValue = thisMonthSpending._sum.total || 0;
  const lastMonthSpendingValue = lastMonthSpending._sum.total || 0;
  const spendingChange = lastMonthSpendingValue > 0
    ? ((thisMonthSpendingValue - lastMonthSpendingValue) / lastMonthSpendingValue) * 100
    : 0;

  const ordersChange = lastMonthOrders > 0
    ? ((thisMonthOrders - lastMonthOrders) / lastMonthOrders) * 100
    : 0;

  return {
    totalOrders,
    activeOrders,
    thisMonthOrders,
    thisMonthSpending: thisMonthSpendingValue,
    spendingChange,
    ordersChange,
    favoriteFarmers,
    businessName: grocer?.businessName || "Your Business",
  };
}

/**
 * Fetch recent orders for the grocer
 */
async function getRecentOrders(grocerId: string, limit: number = 5) {
  return prisma.order.findMany({
    where: { grocerId },
    orderBy: { createdAt: "desc" },
    take: limit,
    include: {
      farmer: {
        include: {
          user: {
            select: { name: true },
          },
        },
      },
      items: {
        select: { id: true },
      },
    },
  });
}

/**
 * Fetch favorite/frequent suppliers
 */
async function getFavoriteSuppliers(grocerId: string, limit: number = 4) {
  // Get farmers the grocer has ordered from most frequently
  const frequentFarmers = await prisma.order.groupBy({
    by: ["farmerId"],
    where: {
      grocerId,
      status: "DELIVERED",
    },
    _count: true,
    _sum: { total: true },
    orderBy: {
      _count: {
        farmerId: "desc",
      },
    },
    take: limit,
  });

  // Fetch farmer details
  const farmerIds = frequentFarmers.map((f) => f.farmerId);
  const farmers = await prisma.farmer.findMany({
    where: { id: { in: farmerIds } },
    include: {
      user: {
        select: { name: true },
      },
      _count: {
        select: { products: { where: { status: "ACTIVE" } } },
      },
    },
  });

  return frequentFarmers.map((ff) => {
    const farmer = farmers.find((f) => f.id === ff.farmerId);
    return {
      id: ff.farmerId,
      farmName: farmer?.farmName || "Unknown Farm",
      ownerName: farmer?.user.name || "Unknown",
      city: farmer?.city || "",
      state: farmer?.state || "",
      rating: farmer?.rating || 0,
      isVerified: farmer?.isVerified || false,
      productCount: farmer?._count.products || 0,
      orderCount: ff._count,
      totalSpent: ff._sum.total || 0,
    };
  });
}

/**
 * Fetch recommended products
 */
async function getRecommendedProducts(grocerId: string, limit: number = 6) {
  // Get products from farmers the grocer has ordered from before
  // or highly rated products
  const products = await prisma.product.findMany({
    where: {
      status: "ACTIVE",
      availableQty: { gt: 0 },
    },
    orderBy: [
      { farmer: { rating: "desc" } },
      { createdAt: "desc" },
    ],
    take: limit,
    include: {
      farmer: {
        select: {
          farmName: true,
          city: true,
          state: true,
          rating: true,
          isVerified: true,
        },
      },
    },
  });

  return products;
}

/**
 * Fetch spending data for chart (last 7 days)
 */
async function getSpendingChartData(grocerId: string) {
  const days = 7;
  const data = [];

  for (let i = days - 1; i >= 0; i--) {
    const date = new Date();
    date.setDate(date.getDate() - i);
    date.setHours(0, 0, 0, 0);

    const nextDate = new Date(date);
    nextDate.setDate(nextDate.getDate() + 1);

    const daySpending = await prisma.order.aggregate({
      where: {
        grocerId,
        status: { notIn: ["CANCELLED", "REFUNDED"] },
        createdAt: {
          gte: date,
          lt: nextDate,
        },
      },
      _sum: { total: true },
      _count: true,
    });

    data.push({
      date: date.toLocaleDateString("en-US", { weekday: "short", month: "short", day: "numeric" }),
      spending: daySpending._sum.total || 0,
      orders: daySpending._count || 0,
    });
  }

  return data;
}

